# scripts/verify_parity.py
"""Verify that all environments are running the same image digest and model."""
import subprocess, json, sys

def get_running_digest(namespace: str) -> str:
    """Return the image digest of the running deployment in a namespace."""
    out = subprocess.run(
        ["kubectl", "get", "deployment", "claude-app", "-n", namespace,
         "-o", "jsonpath={.spec.template.spec.containers[0].image}"],
        capture_output=True, text=True, check=True,
    )
    return out.stdout.strip()

def get_env_var(namespace: str, var: str) -> str:
    """Return an environment variable from the running pod."""
    pod = subprocess.run(
        ["kubectl", "get", "pod", "-n", namespace, "-l", "app=claude-app",
         "-o", "jsonpath={.items[0].metadata.name}"],
        capture_output=True, text=True, check=True,
    ).stdout.strip()
    out = subprocess.run(
        ["kubectl", "exec", pod, "-n", namespace, "--",
         "printenv", var],
        capture_output=True, text=True, check=True,
    )
    return out.stdout.strip()

def verify_parity(namespaces: list[str] = ["dev", "staging", "prod"]):
    digests = {ns: get_running_digest(ns) for ns in namespaces}
    models = {ns: get_env_var(ns, "MODEL_VERSION") for ns in namespaces}
    prompt_hashes = {ns: get_env_var(ns, "PROMPT_HASH") for ns in namespaces}

    violations = []
    unique_digests = set(digests.values())
    unique_models = set(models.values())
    unique_prompts = set(prompt_hashes.values())

    if len(unique_digests) > 1:
        violations.append(f"IMAGE MISMATCH: {digests}")
    if len(unique_models) > 1:
        violations.append(f"MODEL MISMATCH: {models}")
    if len(unique_prompts) > 1:
        violations.append(f"PROMPT MISMATCH: {prompt_hashes}")

    if violations:
        for v in violations:
            print(f"PARITY VIOLATION: {v}")
        sys.exit(1)
    else:
        print("Parity OK: all environments running same image, model, and prompts")
        for ns in namespaces:
            print(f"  {ns}: {digests[ns][:30]}...")

if __name__ == "__main__":
    verify_parity()

# scripts/anonymise_for_staging.py
"""Produce staging test data with the same shape as production records."""
import json, hashlib, random, string

def anonymise_user_message(message: str) -> str:
    """Replace recognisable patterns while preserving message structure."""
    import re
    # Replace email addresses
    message = re.sub(r"[\w.+-]+@[\w-]+\.[\w.]+", "user@example.com", message)
    # Replace phone numbers
    message = re.sub(r"\b\d{3}[-.\s]?\d{3}[-.\s]?\d{4}\b", "555-000-0000", message)
    # Replace names (heuristic: capitalised word pairs)
    message = re.sub(r"\b([A-Z][a-z]+ [A-Z][a-z]+)\b", "John Smith", message)
    return message

def create_staging_fixture(prod_sample: dict) -> dict:
    """Return an anonymised version of a production conversation sample."""
    return {
        "session_id": hashlib.sha256(prod_sample["session_id"].encode()).hexdigest()[:16],
        "messages": [
            {**m, "content": anonymise_user_message(m["content"])}
            if m["role"] == "user" else m
            for m in prod_sample.get("messages", [])
        ],
        "metadata": {k: v for k, v in prod_sample.get("metadata", {}).items()
                     if k not in ("user_id", "account_number", "ip_address")},
    }
